from urllib.parse import urlparse

def get_target_for_redirect(target: str, domain: str) -> str:
    domain_clean = domain.strip().lower()
    if domain_clean.startswith('https://'):
        domain_clean = domain_clean[len('https://'):]
    elif domain_clean.startswith('http://'):
        domain_clean = domain_clean[len('http://'):]
    domain_clean = domain_clean.lstrip('/').rstrip('/').rstrip('.')

    fallback = f'https://{domain_clean}'
    domain_host = domain_clean.split(':', 1)[0].split('@')[-1]
    try:
        domain_host = domain_host.encode('idna').decode('ascii')
    except UnicodeError:
        pass

    try:
        url = target.strip()
        parsed = urlparse(url)
        if parsed.scheme.lower() != 'https':
            return fallback

        host = parsed.hostname
        if not host:
            return fallback

        host = host.lower().rstrip('.')
        try:
            host = host.encode('idna').decode('ascii')
        except UnicodeError:
            pass

        if host == domain_host or host.endswith('.' + domain_host):
            return url
    except Exception:
        pass

    return fallback

