def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base = os.path.realpath(dir_path)
        target = os.path.realpath(os.path.join(base, filename))
        if not (target == base or target.startswith(base + os.sep)):
            return ''
        with open(target, 'r', encoding='utf-8') as f:
            return f.read()
    except Exception:
        return ''

import os
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        dest_real = os.path.realpath(dest_path)
        os.makedirs(dest_real, exist_ok=True)

        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                if not member.name:
                    return False

                name_parts = member.name.replace('\\', '/').split('/')
                if any(part == '..' for part in name_parts):
                    return False
                if os.path.isabs(member.name):
                    return False

                target = os.path.realpath(os.path.join(dest_real, member.name))
                if not (target == dest_real or target.startswith(dest_real + os.sep)):
                    return False

                if member.issym() or member.islnk():
                    link_name = member.linkname
                    if os.path.isabs(link_name):
                        return False

                    if member.islnk():
                        source = os.path.realpath(os.path.join(dest_real, link_name))
                        if not (source == dest_real or source.startswith(dest_real + os.sep)):
                            return False
                        if not os.path.exists(source):
                            return False
                        if os.path.exists(target) or os.path.islink(target):
                            os.remove(target)
                        os.link(source, target)
                    else:
                        link_dir = os.path.dirname(target)
                        resolved_link = os.path.realpath(os.path.join(link_dir, link_name))
                        if not (resolved_link == dest_real or resolved_link.startswith(dest_real + os.sep)):
                            return False
                        if os.path.exists(target) or os.path.islink(target):
                            os.remove(target)
                        os.symlink(link_name, target)

                elif member.isdir():
                    os.makedirs(target, exist_ok=True)

                elif member.isfile():
                    parent = os.path.dirname(target)
                    if parent:
                        os.makedirs(parent, exist_ok=True)
                    src = tar.extractfile(member)
                    if src is None:
                        return False
                    with src, open(target, 'wb') as dst:
                        while True:
                            chunk = src.read(1024 * 1024)
                            if not chunk:
                                break
                            dst.write(chunk)
                else:
                    continue

        return True
    except Exception:
        return False

import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l'],
            cwd=dir_path,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=False,
        )
    except (FileNotFoundError, PermissionError, NotADirectoryError, OSError):
        return ''
    if result.returncode != 0:
        return ''
    return result.stdout

