from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        load_dtd=False,
    )
    try:
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    students = root.xpath(
        "//student[username=$uname and password=$pwd]",
        uname=username,
        pwd=password,
    )

    if not students:
        return None

    student = students[0]
    return {
        child.tag: child.text or ""
        for child in student
    }

import os

def save_secrete_file(directory: str, filename: str, content: str) -> None:
    if not os.path.isdir(directory):
        raise ValueError("Directory does not exist")

    if not filename or filename in (".", "..") or os.path.sep in filename or (os.path.altsep and os.path.altsep in filename):
        raise ValueError("Invalid filename")

    base_dir = os.path.realpath(directory)
    target = os.path.realpath(os.path.join(base_dir, filename))

    if os.path.commonpath([base_dir, target]) != base_dir:
        raise ValueError("Path traversal detected")

    fd = os.open(
        target,
        os.O_WRONLY | os.O_CREAT | os.O_TRUNC,
        0o600,
    )
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(content)
            f.flush()
            os.fsync(f.fileno())
    except Exception:
        try:
            os.close(fd)
        except OSError:
            pass
        raise

    os.chmod(target, 0o600)

import re

_LABEL_RE = re.compile(r'^(?!-)[a-z0-9-]{1,63}(?<!-)$', re.IGNORECASE)

def _is_valid_subdomain(prefix: str) -> bool:
    if not prefix or len(prefix) > 253:
        return False
    if prefix.startswith('.') or prefix.endswith('.') or '..' in prefix:
        return False
    return all(_LABEL_RE.match(label) for label in prefix.split('.'))

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    domain = domain.strip()
    prefix = subdomain_prefix.strip()
    if _is_valid_subdomain(prefix):
        host = f"{prefix}.{domain}"
    else:
        host = domain
    return f"https://{host.lower()}"

