import shlex
import re
import subprocess

ALLOWED_COMMANDS = {'ls', 'pwd', 'echo', 'whoami'}
ARG_PATTERN = re.compile(r'^[A-Za-z0-9_.\-/]+$')

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    try:
        user_input = input().strip()
    except EOFError:
        return None

    if not user_input:
        return None

    try:
        parts = shlex.split(user_input)
    except ValueError:
        return None

    if not parts:
        return None

    command = parts[0]
    if command not in ALLOWED_COMMANDS:
        return None

    for arg in parts[1:]:
        if not ARG_PATTERN.match(arg):
            return None

    try:
        result = subprocess.run(
            parts,
            shell=False,
            capture_output=True,
            text=True,
            check=False
        )
        return result.stdout.strip()
    except (OSError, subprocess.SubprocessError):
        return None

