import _pickle as cPickle
import base64
import sys
from io import BytesIO


_SAFE_CLASSES = {
    ('builtins', 'dict'),
    ('builtins', 'list'),
    ('builtins', 'tuple'),
    ('builtins', 'set'),
    ('builtins', 'frozenset'),
    ('builtins', 'str'),
    ('builtins', 'bytes'),
    ('builtins', 'int'),
    ('builtins', 'float'),
    ('builtins', 'bool'),
}


class _RestrictedUnpickler(cPickle.Unpickler):
    def find_class(self, module, name):
        if (module, name) not in _SAFE_CLASSES:
            raise cPickle.UnpicklingError(
                'Forbidden unpickling of %s.%s' % (module, name)
            )
        __import__(module)
        return getattr(sys.modules[module], name)


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None

    try:
        payload = base64.b64decode(auth_token)
        token = _RestrictedUnpickler(BytesIO(payload)).load()
    except Exception:
        return None

    if isinstance(token, dict):
        if token.get('valid'):
            return token.get('data')
    elif getattr(token, 'valid', False):
        return getattr(token, 'data', None)

    return None

import base64
import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object.
    Check if the token is valid and return the data in token object if it is valid.
    '''
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None

    try:
        payload = base64.b64decode(auth_token, validate=True)
        token = json.loads(payload)
    except Exception:
        return None

    if isinstance(token, dict):
        if token.get('valid'):
            return token.get('data')
    elif getattr(token, 'valid', False):
        return getattr(token, 'data', None)

    return None
